import{c as a,Q as n,j as s,m as o}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"世界里还有什么:流体、物品、生物群系、光照、粒子","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/10-世界里还有什么-流体物品生物群系光照粒子.md","filePath":"minecraftLearning/10-世界里还有什么-流体物品生物群系光照粒子.md","lastUpdated":1781677803000}'),e={name:"minecraftLearning/10-世界里还有什么-流体物品生物群系光照粒子.md"};function l(i,t,r,d,p,u){return n(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="世界里还有什么-流体、物品、生物群系、光照、粒子" tabindex="-1">世界里还有什么:流体、物品、生物群系、光照、粒子 <a class="header-anchor" href="#世界里还有什么-流体、物品、生物群系、光照、粒子" aria-label="Permalink to &quot;世界里还有什么:流体、物品、生物群系、光照、粒子&quot;">​</a></h1><p>讲完方块、方块实体、实体,大多数人会觉得&quot;世界的构成讲完了&quot;。其实没有。如果你把一个坐标剖开看,会发现上面叠着的东西远不止&quot;一个方块&quot;。这一篇要补上那些<strong>和方块平行存在、却容易被忽略</strong>的对象与数据层。</p><p>它们不属于前三类,但每一类都实打实地占着坐标、影响着世界的行为。漏掉它们,你对&quot;世界由什么构成&quot;的理解就是残缺的。</p><blockquote><p>一句话先记住:<strong>同一个坐标 (x, y, z) 上,不是只有一个方块,而是叠着方块 + 流体 + 光照好几层数据;此外还有生物群系给区域贴标签、物品寄生在容器里、粒子只活在客户端。</strong> 方块只是这叠数据里最显眼的一层。</p></blockquote><hr><h2 id="一、流体-fluidstate-最该补上的-第四套系统" tabindex="-1">一、流体 FluidState:最该补上的&quot;第四套系统&quot; <a class="header-anchor" href="#一、流体-fluidstate-最该补上的-第四套系统" aria-label="Permalink to &quot;一、流体 FluidState:最该补上的&quot;第四套系统&quot;&quot;">​</a></h2><p>这是最容易被忽略、却真正和方块<strong>平行存在</strong>的一类。</p><p>关键事实:<strong>世界里每个坐标同时持有一个 BlockState 和一个 FluidState</strong>,两者是<strong>半独立</strong>的。</p><ul><li>对绝大多数方块,FluidState 是&quot;空&quot;(<code>Fluids.EMPTY</code>)。</li><li>水源方块:它的 BlockState 是水,<strong>同时</strong>有一个非空的 FluidState。</li><li>含水(waterlogging)就是靠这个实现的。</li></ul><h3 id="含水机制-两层状态叠在一格上" tabindex="-1">含水机制:两层状态叠在一格上 <a class="header-anchor" href="#含水机制-两层状态叠在一格上" aria-label="Permalink to &quot;含水机制:两层状态叠在一格上&quot;">​</a></h3><p>你能给楼梯、栅栏、台阶&quot;灌水&quot;,底层是这样的:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>坐标 (10, 64, 20)</span></span>
<span class="line"><span>├── BlockState : oak_stairs[facing=east, half=bottom, waterlogged=true]</span></span>
<span class="line"><span>└── FluidState : water[level=8]   ← 与方块叠加,各管各的</span></span></code></pre></div><p><strong>方块仍然是楼梯</strong>(碰撞、外形、掉落都按楼梯走),但这一格<strong>额外</strong>承载了一份流动的水。<code>waterlogged</code> 这个布尔属性只是 BlockState 用来&quot;记得自己含水&quot;的标记,真正的水行为(流动、推动实体、淹没)由那层独立的 FluidState 负责。</p><h3 id="独立的-tick-队列" tabindex="-1">独立的 tick 队列 <a class="header-anchor" href="#独立的-tick-队列" aria-label="Permalink to &quot;独立的 tick 队列&quot;">​</a></h3><p>回忆存储那一篇里 chunk NBT 同时存了 <code>block_ticks</code> 和 <code>fluid_ticks</code> —— 它们是<strong>两个独立队列</strong>,不是一个。流体的扩散、衰减全在自己的队列里跑:</p><table tabindex="0"><thead><tr><th>概念</th><th>含义</th></tr></thead><tbody><tr><td>level 0–7(内部 1–8)</td><td>流动水的&quot;高度/能量&quot;,离源越远越低</td></tr><tr><td>衰减</td><td>水平每流一格 level -1,到 0 就停;竖直下落不衰减</td></tr><tr><td>找洞</td><td>流动前会探测附近能向下掉的方向,优先朝坑铺</td></tr><tr><td>源方块</td><td>特殊标记,周围两个源能互相补成新源(无限水)</td></tr></tbody></table><p>所以你看到的&quot;水慢慢铺开&quot;,本质是 FluidState 在它自己的 tick 队列里<strong>一圈一圈衰减扩散</strong>,跟方块的 random tick 完全是两套机制。</p><h3 id="踩坑-反直觉" tabindex="-1">踩坑 / 反直觉 <a class="header-anchor" href="#踩坑-反直觉" aria-label="Permalink to &quot;踩坑 / 反直觉&quot;">​</a></h3><ul><li><strong>流体不是方块</strong>:1.13(&quot;扁平化&quot;)之前,水<strong>就是</strong>普通方块,所以那时做不了含水栅栏。1.13 把流体从方块里拆出来、独立成 FluidState 这套系统,含水机制才成为可能。这是一次典型的&quot;把耦合的两个概念解耦&quot;的架构重构。</li><li><strong>挖掉含水楼梯</strong>:楼梯没了,但那层 FluidState 还在,于是水&quot;接管&quot;了这格 —— 这就是为什么破坏含水方块后原地会留下水。</li></ul><hr><h2 id="二、物品-itemstack-寄生在容器里的纯数据" tabindex="-1">二、物品 ItemStack:寄生在容器里的纯数据 <a class="header-anchor" href="#二、物品-itemstack-寄生在容器里的纯数据" aria-label="Permalink to &quot;二、物品 ItemStack:寄生在容器里的纯数据&quot;">​</a></h2><p>物品是和方块<strong>地位相当</strong>的一大类,只是它<strong>不直接待在世界格子里</strong>,而是住在&quot;容器&quot;里。</p><ul><li>容器 = 背包、箱子(方块实体)、漏斗、玩家手上……</li><li>一个 <strong>ItemStack</strong> = 物品种类 + 数量 + 一组组件(耐久、附魔、自定义名等)。1.20.5 后这些附加信息从旧的 NBT <code>tag</code> 迁移成了&quot;数据组件&quot;。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ItemStack</span></span>
<span class="line"><span>├── item   : minecraft:diamond_sword   (种类,注册表里的类型)</span></span>
<span class="line"><span>├── count  : 1</span></span>
<span class="line"><span>└── components</span></span>
<span class="line"><span>    ├── damage      : 12</span></span>
<span class="line"><span>    ├── enchantments: { sharpness: 5 }</span></span>
<span class="line"><span>    └── custom_name : &quot;断钢&quot;</span></span></code></pre></div><h3 id="寄生型类别" tabindex="-1">寄生型类别 <a class="header-anchor" href="#寄生型类别" aria-label="Permalink to &quot;寄生型类别&quot;">​</a></h3><p>物品自身是纯数据,<strong>必须依附在某个宿主里才能存在</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在箱子里 ─► 挂在箱子的方块实体的 Items 列表下</span></span>
<span class="line"><span>在背包里 ─► 挂在玩家实体数据下</span></span>
<span class="line"><span>扔到地上 ─► 被一个 ItemEntity(实体)&quot;装着&quot;进入世界,有了坐标和速度</span></span></code></pre></div><p>最后一种最能说明问题:<strong>同一份剑的数据,在箱子里时挂在方块实体下,扔出去时原样搬进一个实体里</strong>。物品本身没变,变的是&quot;谁在容纳它&quot;。这也是物品和方块、实体三者通过同一套序列化(NBT/组件)互相衔接的缩影。</p><hr><h2 id="三、生物群系-biome-坐标上的-气候标签" tabindex="-1">三、生物群系 Biome:坐标上的&quot;气候标签&quot; <a class="header-anchor" href="#三、生物群系-biome-坐标上的-气候标签" aria-label="Permalink to &quot;三、生物群系 Biome:坐标上的&quot;气候标签&quot;&quot;">​</a></h2><p>生物群系也绑定到坐标,但和方块很不一样。</p><ul><li><strong>粒度粗</strong>:不是每格一个,而是 <strong>4×4×4 一格</strong>。一个 16³ 的 section 只有 <code>4×4×4 = 64</code> 个生物群系格,同样用 palette 压缩(和方块状态用的是同一套调色板思路,只是分辨率低 4 倍)。</li><li><strong>它不&quot;占地方&quot;</strong>,而是给一片区域贴一个标签,决定:</li></ul><table tabindex="0"><thead><tr><th>影响</th><th>例子</th></tr></thead><tbody><tr><td>气候</td><td>温度、湿度、是否下雪/下雨</td></tr><tr><td>刷怪</td><td>这片区域刷什么怪、刷不刷</td></tr><tr><td>染色</td><td>草、树叶、水的<strong>颜色</strong>(同样的草方块在沼泽和平原是不同绿)</td></tr><tr><td>地物</td><td>生成什么植被、结构、矿物分布倾向</td></tr></tbody></table><h3 id="反直觉" tabindex="-1">反直觉 <a class="header-anchor" href="#反直觉" aria-label="Permalink to &quot;反直觉&quot;">​</a></h3><p>你<strong>挖不到、也撞不上</strong>&quot;生物群系&quot;。它是一层无处不在的数据,而非可交互的对象 —— 这是它和&quot;看起来也铺满世界&quot;的方块最根本的区别:方块是实体化的格子内容,生物群系是贴在格子上的元数据。</p><hr><h2 id="四、光照-light-逐格的数值场" tabindex="-1">四、光照 Light:逐格的数值场 <a class="header-anchor" href="#四、光照-light-逐格的数值场" aria-label="Permalink to &quot;四、光照 Light:逐格的数值场&quot;">​</a></h2><p>光照是又一个<strong>逐格存在、绑定坐标、要进 chunk</strong> 的数据层,但它不是&quot;东西&quot;,而是一个 0–15 的<strong>数值场</strong>。</p><p>关键:光有<strong>两个独立通道</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>坐标 (x, y, z)</span></span>
<span class="line"><span>├── BlockLight : 0–15   ← 火把/岩浆/萤石等&quot;光源&quot;发出的光</span></span>
<span class="line"><span>└── SkyLight   : 0–15   ← 天空照下来的光(随昼夜与深度衰减)</span></span></code></pre></div><ul><li>存储:每格 <strong>4 bit</strong>,按 section 存成 <code>BlockLight</code> / <code>SkyLight</code> 两个 Byte_Array(存储那一篇见过)。两个通道分开存,因为一个跟时间无关(火把),一个跟昼夜有关(天光),渲染时要分别处理。</li><li><strong>传播靠洪水填充(flood-fill)</strong>:放下一支火把,光以&quot;每跨一格 -1&quot;的方式向四周扩散;挖掉一格不透明方块,光要重新灌进新腾出的空间。</li></ul><h3 id="踩坑-光照是著名性能热点" tabindex="-1">踩坑:光照是著名性能热点 <a class="header-anchor" href="#踩坑-光照是著名性能热点" aria-label="Permalink to &quot;踩坑:光照是著名性能热点&quot;">​</a></h3><p>这套&quot;光照引擎&quot;在方块频繁变动时要做大量的重新传播,历史上是 Minecraft 的卡顿大户 —— Starlight、Phosphor 这类著名 mod 专门重写它来优化。原因正是 flood-fill 的级联:改一格可能引发一大片光值重算,和红石的更新风暴是同类问题。</p><hr><h2 id="五、粒子-particle-纯客户端的-视觉幽灵" tabindex="-1">五、粒子 Particle:纯客户端的&quot;视觉幽灵&quot; <a class="header-anchor" href="#五、粒子-particle-纯客户端的-视觉幽灵" aria-label="Permalink to &quot;五、粒子 Particle:纯客户端的&quot;视觉幽灵&quot;&quot;">​</a></h2><p>火焰、烟、药水雾、爆炸碎屑这些:</p><ul><li><strong>只存在于客户端</strong>:服务端不存、不 tick,存盘里完全没有它们。</li><li><strong>没有逻辑、不可交互</strong>:纯渲染效果。</li><li>它和实体长得像(有坐标、会动),但<strong>完全是另一类东西</strong>。</li></ul><p>这解释了几个现象:粒子从不影响游戏结果;多人游戏里别人看到的粒子可能和你不完全一样(因为各自客户端独立生成);把画质调低关掉粒子,玩法毫发无损。</p><blockquote><p>严格说粒子不算&quot;世界数据&quot;,它是渲染层的产物。但既然在讨论&quot;世界里还有什么&quot;,必须点明它的存在,以及它和实体的界线 —— <strong>能存盘、能影响逻辑的才是世界对象,粒子两样都不是。</strong></p></blockquote><hr><h2 id="六、声音-soundevent-粒子的-听觉版" tabindex="-1">六、声音 SoundEvent:粒子的&quot;听觉版&quot; <a class="header-anchor" href="#六、声音-soundevent-粒子的-听觉版" aria-label="Permalink to &quot;六、声音 SoundEvent:粒子的&quot;听觉版&quot;&quot;">​</a></h2><p>粒子是纯客户端的视觉幽灵,声音几乎是它的镜像——<strong>纯客户端的听觉表现层</strong>。</p><ul><li>和粒子一样:基本只活在客户端,<strong>触发即播放、不存盘、不参与任何世界状态</strong>。挖方块、走路、怪叫,服务端广播一个&quot;在这个坐标播这个音效&quot;的事件,各客户端自己去放,放完就没了。</li><li><code>SoundEvent</code> 是注册表里的一个类型(和方块、物品一样上户口,呼应注册表那一篇)。它本身只是个 ID(如 <code>minecraft:block.stone.break</code>);客户端拿到这个 ID,按资源包里的 <code>sounds.json</code> 查到实际的音频文件去播放。换皮资源包能改音效,就是改这张映射表。</li><li>有坐标、会<strong>随距离衰减、声像偏移</strong>(左右声道),但这些都只是给玩家听的——对世界逻辑零影响。</li></ul><h3 id="和-游戏事件-gameevent-振动-要分清" tabindex="-1">和&quot;游戏事件 GameEvent / 振动&quot;要分清 <a class="header-anchor" href="#和-游戏事件-gameevent-振动-要分清" aria-label="Permalink to &quot;和&quot;游戏事件 GameEvent / 振动&quot;要分清&quot;">​</a></h3><p>这两个最容易混,因为同一个动作往往<strong>两者都发</strong>:</p><table tabindex="0"><thead><tr><th></th><th>SoundEvent</th><th>GameEvent / 振动</th></tr></thead><tbody><tr><td>给谁</td><td>给玩家<strong>听</strong></td><td>给<strong>幽匿感测体 / 监守者</strong>监听</td></tr><tr><td>属于</td><td>纯表现层</td><td>玩法层的瞬时信号</td></tr><tr><td>影响世界</td><td>否</td><td><strong>是</strong>(触发红石、招怪)</td></tr><tr><td>存盘</td><td>否</td><td>否(瞬时)</td></tr></tbody></table><p>举例:你放一个方块,服务端既播一个 <code>SoundEvent</code>(让你听见&quot;咚&quot;),又发一个 <code>GameEvent</code>(让附近幽匿感测体能&quot;感觉到&quot;你动了)。前者纯装饰,后者是会被玩法机制消费的真信号。<strong>潜行能消除振动(GameEvent)却消不掉某些声音</strong>,正是因为它们是两套独立的东西。</p><p>所以:<strong>声音 + 粒子共同构成&quot;纯表现层&quot;</strong>——都有坐标、都会传播衰减,但都不存盘、都对世界逻辑毫无影响。它们是世界&quot;长什么样、听起来怎样&quot;的产物,而不是世界&quot;是什么&quot;的一部分。</p><hr><h2 id="七、把一格剖开-多层叠加" tabindex="-1">七、把一格剖开:多层叠加 <a class="header-anchor" href="#七、把一格剖开-多层叠加" aria-label="Permalink to &quot;七、把一格剖开:多层叠加&quot;">​</a></h2><p>把前面几层合起来看,一个坐标的真实构成是这样的:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>坐标 (x, y, z) ───────────────────────────────</span></span>
<span class="line"><span>  ├── BlockState   方块状态(网格,可共享,palette)</span></span>
<span class="line"><span>  ├── FluidState   流体状态(与方块叠加,独立 tick)</span></span>
<span class="line"><span>  ├── BlockLight   光源光照(0–15,4 bit)</span></span>
<span class="line"><span>  ├── SkyLight     天空光照(0–15,4 bit)</span></span>
<span class="line"><span>  └──(可能)BlockEntity   少数方块的附加数据/渲染</span></span>
<span class="line"><span></span></span>
<span class="line"><span>区域级(4×4×4 一格):</span></span>
<span class="line"><span>  └── Biome        气候/染色/刷怪标签</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不在格子里:</span></span>
<span class="line"><span>  ├── ItemStack    寄生在容器/实体中的物品数据</span></span>
<span class="line"><span>  └── Particle     纯客户端视觉,不占数据</span></span></code></pre></div><p><strong>最反直觉、也最关键的一点</strong>:一格上叠着方块 + 流体 + 双通道光照好几层,它们各自独立存储、独立更新。&quot;一格 = 一个方块&quot;是新手最容易先入为主、却最该被打破的错觉。</p><hr><h2 id="串联" tabindex="-1">串联 <a class="header-anchor" href="#串联" aria-label="Permalink to &quot;串联&quot;">​</a></h2><ul><li>承接方块三层那一篇:方块、方块实体是&quot;格子内容&quot;和它的附加;这一篇补的流体、光照是<strong>叠在同一格上的另外几层</strong>,生物群系是<strong>贴在格子上的标签</strong>,物品是<strong>寄生在容器里的数据</strong>。合起来,&quot;世界里的对象类别&quot;才算齐。</li><li>呼应存储那一篇:chunk NBT 里的 <code>biomes</code>(4×4×4 palette)、<code>BlockLight</code>/<code>SkyLight</code>(Byte_Array)、<code>fluid_ticks</code>(独立队列)正是这一篇这些数据层的落盘形态 —— 你在磁盘上看到的字段,对应的就是这里讲的运行时分层。</li><li>指向注册表那一篇:这里每一类的<strong>类型</strong>(每种流体、每种物品、每种生物群系)同样登记在注册表里;生物群系更是&quot;数据驱动的动态注册表&quot;的典型,留到下一篇展开。</li></ul><p>这一篇之后,&quot;世界里的逐实例对象/数据层&quot;基本就穷举完了:方块、流体、方块实体、实体、物品、生物群系、光照,外加不算世界数据的粒子。再往上,就是把这一切<strong>类型</strong>装起来的元系统了。</p>`,67)])])}const g=a(e,[["render",l]]);export{h as __pageData,g as default};
